script:
frappe.ui.form.on("Book Copy", {
    library_book(frm) {

        if (!frm.doc.library_book) return;

        frappe.db.get_doc("Library Book", frm.doc.library_book).then(doc => {

            frm.set_value("rack", doc.rack_location);

            if (frm.fields_dict.isbn) {
                frm.set_value("isbn", doc.isbn);
            }

        });

    }
});
